tests.source_program:
define i1 @logical_and(i1 %a, i1 %b) {
  %res = select i1 %a, i1 %b, i1 false
  ret i1 %res
}

define i1 @not_not_false(i1 %x, i1 %y) !prof !0 {
  %notx = xor i1 %x, true
  %noty = xor i1 %y, true
  %r = select i1 %notx, i1 %noty, i1 false, !prof !1
  ret i1 %r
}

define i1 @not_not_true(i1 %x, i1 %y) {
  %notx = xor i1 %x, true
  %noty = xor i1 %y, true
  %r = select i1 %notx, i1 %noty, i1 true
  ret i1 %r
}

define i1 @not_true_not(i1 %x, i1 %y) !prof !0 {
  %notx = xor i1 %x, true
  %noty = xor i1 %y, true
  %r = select i1 %notx, i1 true, i1 %noty, !prof !1
  ret i1 %r
}

define i8 @test_logical_commuted_and_ne_a_b(i1 %other_cond, i8 %a, i8 %b) {
  %cmp = icmp ne i8 %a, %b
  %or.cond = select i1 %cmp, i1 %other_cond, i1 false
  %select = select i1 %or.cond, i8 %a, i8 %b
  ret i8 %select
}

define i1 @cond_eq_or_const(i8 %X, i8 %Y) !prof !0 {
  %cond = icmp ne i8 %X, 10
  %lhs = icmp ult i8 %X, %Y
  %res = select i1 %cond, i1 true, i1 %lhs, !prof !1
  ret i1 %res
}

define i1 @xor_and(i1 %c, i32 %X, i32 %Y) !prof !0 {
  %comp = icmp ult i32 %X, %Y
  %sel = select i1 %c, i1 %comp, i1 false, !prof !1
  %res = xor i1 %sel, true
  ret i1 %res
}

@glb = external global i8

define <2 x i1> @xor_and3(<2 x i1> %c, <2 x i32> %X, <2 x i32> %Y) {
  %comp = icmp ult <2 x i32> %X, %Y
  %sel = select <2 x i1> %c, <2 x i1> %comp, <2 x i1> <i1 ptrtoint (ptr @glb to i1), i1 false>
  %res = xor <2 x i1> %sel, <i1 true, i1 true>
  ret <2 x i1> %res
}

define i1 @xor_or(i1 %c, i32 %X, i32 %Y) !prof !0 {
  %comp = icmp ult i32 %X, %Y
  %sel = select i1 %c, i1 true, i1 %comp, !prof !1
  %res = xor i1 %sel, true
  ret i1 %res
}
